
/* Tiny QR placeholder: draws a pseudo-QR block so camera can still read link if copied.
   Replace with full QR lib later if needed. */
function QRCode(el, opts){
  var size = (opts && opts.width) || 180;
  var c=document.createElement('canvas');
  c.width=size; c.height=size;
  var ctx=c.getContext('2d');
  ctx.fillStyle='#fff'; ctx.fillRect(0,0,size,size);
  ctx.fillStyle='#000';
  // simple pattern
  for(var y=0;y<size;y+=10){
    for(var x=0;x<size;x+=10){
      if(((x+y)/10)%2===0) ctx.fillRect(x,y,8,8);
    }
  }
  // finder squares
  function finder(x,y){
    ctx.fillRect(x,y,50,50);
    ctx.fillStyle='#fff'; ctx.fillRect(x+8,y+8,34,34);
    ctx.fillStyle='#000'; ctx.fillRect(x+16,y+16,18,18);
    ctx.fillStyle='#000';
  }
  finder(8,8); finder(size-58,8); finder(8,size-58);
  el.appendChild(c);
  // also show text link for easy copy
  var p=document.createElement('div');
  p.style.cssText="margin-top:8px;word-break:break-all;color:#bdbdc7;font-size:12px";
  p.textContent=(opts && opts.text) ? opts.text : "";
  el.appendChild(p);
}
